class Solution:
    def powerfulIntegers(self, x: int, y: int, bound: int) -> List[int]:
        result = set()
        for i in range(32):
            for j in range(32):
                if x**i + y**j <= bound:
                    result.add(x**i + y**j)
        return list(result)
